MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS { (sm)-[:HAS_SEMANTIC_ID]->(:SemanticConcept {id: "https://admin-shell.io/dfki/SubmodelTemplate/FacilityInformation/1/0"}) }
RETURN aas.idShort, aas.id, sm.idShort, sm.id

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS { (sm)-[:HAS_SEMANTIC_ID]->(:SemanticConcept {id: "https://admin-shell.io/idta/SubmodelTemplate/technicaldataagv/1/0"}) }
RETURN aas.idShort, aas.id, sm.idShort, sm.id

MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(asset:Asset)
WHERE EXISTS {
  MATCH (asset)-[:HAS_SPECIFIC_ASSET_ID]->(specificId)
  WHERE specificId.name = 'serialNumber' AND specificId.value = $serialNumber
}
RETURN aas.id AS aas_id, aas.idShort, asset.globalAssetId
